class Solution:
    def countSeniors(self, details):
        count = 0
        for s in details:
            age = int(s[-4:-2])
            if age > 60:
                count += 1
        return count

solutions.python:
class Solution:
    def countSeniors(self, details):
        count = 0
        for s in details:
            if int(s[11:13]) > 60:
                count += 1
        return count

solutions.javascript:
var countSeniors = function(details) {
    let count = 0;
    for (const s of details) {
        if (parseInt(s.substring(11, 13), 10) > 60) count += 1;
    }
    return count;
};
